-- Migration 010: Russian versions of the three seed blog posts
-- Adds Russian translations of Welcome, How to Start, and Story Behind posts

BEGIN;

INSERT INTO blog_posts (author_id, title, slug, content, excerpt, language, tags, is_published, published_at)
VALUES
(
    28,
    'Добро пожаловать в блог Savchenko Solutions',
    'dobro-pozhalovat-v-blog-savchenko-solutions',
    E'## Зачем блог?\n\nУже более двух лет Savchenko Solutions тихо работает: авторы загружают решения, студенты их находят, и цикл продолжается. Но за каждым решением стоит история — оригинальный приём, тонкое физическое наблюдение или трудный урок о том, чего делать **не стоит**. Этим историям негде было жить. До сих пор.\n\nЭтот блог — место, где мы отступаем от отдельных задач и говорим о более широкой картине: как эффективно изучать физику, что делает задачник Савченко уникальным и как небольшой open-source проект вырос в платформу, которой пользуются студенты в более чем 150 странах.\n\n## Чего ожидать\n\nМы планируем публиковать материалы, полезные как новым посетителям, так и давним авторам:\n\n**Руководства по подготовке.** С каких глав начать? Как выстроить математический аппарат, который Савченко предполагает уже освоенным? Мы поделимся конкретными планами, основанными на опыте десятков авторов, прошедших через эти задачи.\n\n**Разборы отдельных задач.** Некоторые задачи Савченко славятся тем, что выглядят обманчиво простыми, но требуют настоящей изобретательности. Мы будем разбирать по одной задаче за раз, показывая не только решение, но и *процесс мышления* — ложные ходы, ключевую идею и почему ответ физически разумен.\n\n**Обновления платформы.** Когда мы запускаем новые функции, исправляем давние ошибки или достигаем вех, вы узнаете об этом здесь первыми. Мы верим в открытую разработку, и этот блог — часть этого.\n\n**Истории авторов.** У Savchenko Solutions 72 автора из 18 стран. Среди них — тренеры олимпиадных команд и студенты, впервые открывающие задачник. Мы хотим рассказать их истории.\n\n## Кто здесь пишет?\n\nЛюбой пользователь с подтверждённым аккаунтом автора может писать посты в блог. Тем не менее мы начнём с небольшой редакционной команды, чтобы задать тон и планку качества. Если вам интересно писать — свяжитесь с нами.\n\n## Глобальная миссия\n\n«Задачи по физике» О. Я. Савченко — один из самых строгих задачников в постсоветской физической традиции. Десятилетиями он был доступен в основном русскоязычным студентам. Наша миссия — сделать каждое решение доступным, рецензированным и бесплатным — на английском и русском языках.\n\nБлог — продолжение этой миссии. Хорошее физическое образование — это не только правильный ответ; это понимание *почему* ответ правильный, *как* его найти и *чему* он учит о физическом мире.\n\nДобро пожаловать. Мы рады, что вы здесь.\n\n---\n\n*Есть тема, которую вы хотели бы увидеть? Оставьте комментарий или напишите нам на aliaksandr@melnichenka.com.*',
    'Представляем блог Savchenko Solutions: руководства по подготовке, разборы задач, обновления платформы и истории авторов.',
    'ru',
    ARRAY['announcement', 'meta'],
    true,
    NOW() - INTERVAL '2 days'
),
(
    28,
    'Как начать решать задачи Савченко',
    'kak-nachat-reshat-zadachi-savchenko',
    E'## Проблема репутации\n\nЗадачник Савченко славится своей невероятной сложностью. Эта репутация отчасти заслужена — поздние главы по электродинамике, оптике и теории относительности содержат задачи, которые бросают вызов даже аспирантам. Но ранние главы удивительно доступны, если подойти к ним с правильной подготовкой и настроем.\n\nЭто руководство для тех, кто слышал о Савченко, заинтересовался и хочет составить практический план.\n\n## Необходимая подготовка\n\nПрежде чем открыть задачник, убедитесь, что вы уверенно владеете:\n\n- **Кинематикой в одном и двух измерениях.** Вы должны уметь выбирать систему координат, записывать уравнения движения и решать их. Если движение снаряда ещё вызывает затруднения — сначала укрепите эту базу.\n- **Законами Ньютона.** Построение схем сил должно быть на автомате. Вы должны без колебаний разбирать системы из двух-трёх связанных тел.\n- **Основами математического анализа.** Многие задачи Савченко требуют дифференцирования и интегрирования. Вам не нужен курс мат. анализа, но необходимо свободно работать с производными, интегралами и решать простые дифференциальные уравнения вида $\\frac{dv}{dt} = -kv$.\n- **Тригонометрией и геометрией.** Савченко любит геометрические рассуждения. Теорема косинусов, свойства подобных треугольников и основы стереометрии вам пригодятся.\n\nЕсли что-то из этого ещё слабо — потратьте несколько недель на укрепление, прежде чем приступать. Задачи Савченко вознаграждают подготовку, а не грубую силу.\n\n## Рекомендуемый порядок\n\n**Не** начинайте с задачи 1.1.1 и не решайте подряд. Вместо этого попробуйте такой путь:\n\n### Фаза 1: Набрать уверенность (недели 1–4)\n\nНачните с **Главы 1 (Кинематика)**, разделы 1.1–1.3. Эти задачи варьируются от простых до умеренно хитрых и развивают ключевые навыки работы с системами отсчёта и анализа движения.\n\nЗатем перейдите к **Главе 2 (Динамика)**, разделы 2.1–2.3. Задачи на второй закон Ньютона у Савченко превосходны, потому что заставляют точно определять, какие силы действуют на какое тело.\n\nСтремитесь решать 3–5 задач в день. Качество важнее количества.\n\n### Фаза 2: Расширить инструментарий (недели 5–10)\n\nТеперь возьмитесь за **Главу 3 (Энергия и импульс)**. Законы сохранения энергии и импульса — рабочие лошадки физики, и задачи Савченко в этой главе проверят вашу способность выбирать правильный закон сохранения.\n\nДобавьте **Главу 5 (Термодинамика)**, разделы 5.1–5.3. Задачи на идеальный газ — естественный следующий шаг, знакомящий со стилем Савченко в другой области.\n\n### Фаза 3: Сложные темы (недели 11+)\n\nС прочным фундаментом можно переходить к:\n- **Глава 4 (Вращение)** — задачи на момент импульса и момент силы\n- **Глава 6 (Электростатика)** — задачи Савченко по электростатике легендарны\n- **Глава 7 (Постоянный ток)** — анализ цепей с физическим уклоном\n\nГлавы 11–14 (Электродинамика, Оптика, Относительность, Квантовая физика) оставьте до тех пор, пока не наберёте серьёзный опыт.\n\n## Как работать над задачей\n\n1. **Прочитайте задачу дважды.** Первый раз — чтобы понять суть, второй — чтобы выделить данные.\n2. **Нарисуйте схему.** Даже если кажется, что это не нужно. Задачи Савченко часто содержат геометрические тонкости, которые видны только на чертеже.\n3. **Определите физику.** Какие законы сохранения применимы? Какие есть связи? Какие величины даны, а какие неизвестны?\n4. **Запишите уравнения, прежде чем подставлять числа.** Работайте в общем виде как можно дольше. Буквенные ответы легче проверить размерностно и они раскрывают физические зависимости.\n5. **Проверьте ответ.** Правильная ли размерность? Правильно ли он ведёт себя в предельных случаях? Если $m \\to 0$ или $v \\to 0$, имеет ли ответ физический смысл?\n\n## Когда вы застряли\n\nЗастрять — нормально. Задачи Савченко *специально* требуют творческого мышления. Вот что делать:\n\n- **Отойдите на 15 минут.** Серьёзно. Ваше подсознание продолжит работать.\n- **Попробуйте другой подход.** Если закон сохранения энергии не работает — попробуйте анализ сил. Если декартовы координаты дают громоздкие выражения — попробуйте полярные.\n- **Посмотрите решение, но активно.** Когда вы проверяете наши решения на SavchenkoSolutions.com, не читайте их пассивно. Найдите ключевой шаг, который вы пропустили, закройте решение и завершите задачу самостоятельно.\n- **Вернитесь к трудным задачам позже.** Отметьте задачи, которые не смогли решить, и вернитесь к ним через неделю. Вы удивитесь, как часто ответ становится очевидным после накопленного опыта.\n\n## Игра вдолгую\n\nСавченко — это марафон, а не спринт. Больше всего выигрывают те студенты, которые работают систематично на протяжении месяцев, выстраивая глубокое и гибкое понимание физики. В задачнике 2023 задачи. Никто не ждёт, что вы решите их все. Даже 200–300 задач из грамотно подобранной выборки преобразят ваш уровень.\n\nУдачи. И когда вы решите задачу, для которой ещё нет решения на нашем сайте, подумайте о том, чтобы загрузить своё. Так растёт это сообщество.\n\n---\n\n*Вопросы о том, с чего начать? Оставьте комментарий, и мы поможем составить индивидуальный план.*',
    'Практическое руководство по задачнику Савченко: необходимая подготовка, рекомендуемый порядок глав, методика решения задач и что делать, когда вы застряли.',
    'ru',
    ARRAY['guide', 'study-tips', 'beginners'],
    true,
    NOW() - INTERVAL '1 day'
),
(
    28,
    'История Savchenko Solutions',
    'istoriya-savchenko-solutions',
    E'## Один студент, одна задача за раз\n\nSavchenko Solutions начался в конце 2023 года как личный проект. Я работал над задачником Савченко «Задачи по физике» и обнаружил, что хорошие решения разбросаны по малоизвестным форумам, рукописным PDF-файлам разного качества и русскоязычным сайтам, недоступным для иностранных студентов. Единого надёжного открытого ресурса не существовало.\n\nИ я начал его создавать. Первая версия была статическим сайтом на GitHub Pages — простые HTML-файлы, по одному на задачу, с решениями в LaTeX, отрендеренными через MathJax. Без базы данных, без аккаунтов пользователей, без интерактивности. Только решения.\n\nВ первый месяц было, может быть, 50 посетителей. Большинство из них, вероятно, был я сам, обновляя страницу, чтобы проверить, правильно ли рендерится MathJax.\n\n## Переход на настоящую платформу\n\nК середине 2024 года статический сайт вырос до нескольких сотен решений, и его ограничения стали очевидны. Редактирование решения означало коммит HTML в Git-репозиторий. Другие люди не могли вносить вклад, не зная Git. На сайте не было поиска, способа отслеживать, какие задачи решены, и механизма контроля качества.\n\nВ конце 2024 года я перестроил всю платформу как серверное приложение на Express.js с базой данных PostgreSQL. Решения были перенесены из сырого HTML в Markdown. Были добавлены аккаунты пользователей, отслеживание вклада и интерфейс редактирования. 11 493 правки эпохи GitHub Pages были сохранены в отдельной таблице `github_contributions`, чтобы история авторов никогда не терялась.\n\nЭта миграция стала переломным моментом. Через несколько недель авторы, которые раньше присылали мне исправления по email, могли редактировать решения напрямую.\n\n## Рост в цифрах\n\nЦифры рассказывают историю сообщества, которое выросло органически, почти исключительно через сарафанное радио:\n\n- **1 516 решений** опубликовано на английском и русском языках\n- **72 автора** из **18 стран** внесли правки\n- **710 зарегистрированных пользователей** создали аккаунты\n- **150 000+ уникальных посетителей** из **150+ стран** воспользовались сайтом\n- **6 311 правок** сделано после миграции платформы\n- **17 804 правки** всего, включая эпоху GitHub Pages\n\nСамые крупные сообщества авторов — в России, США, Грузии, Белоруссии и Казахстане — сочетание, отражающее как постсоветские корни задачника, так и его растущую международную аудиторию.\n\n## Сюжет на LEX 18\n\nВ начале 2025 года местная телестанция LEX 18 в Лексингтоне, Кентукки, выпустила репортаж о проекте. Это было сюрреалистично — сайт для решения задач по физике обсуждается в вечерних новостях рядом с прогнозом погоды и школьным спортом. Но история нашла отклик: созданная студентом платформа, делающая элитное физическое образование бесплатно доступным.\n\nВсплеск трафика после этого репортажа познакомил нас с новой аудиторией американских учителей физики и студентов, которые никогда не слышали о Савченко, но сразу оценили строгость и глубину задач.\n\n## Как работают авторы\n\nКаждое решение на сайте проходит простой, но эффективный процесс:\n\n1. Автор пишет или редактирует решение с помощью нашего Markdown-редактора с предпросмотром MathJax.\n2. Правка сохраняется и сразу становится видна (мы доверяем нашим авторам, и каждая правка версионируется).\n3. Другие авторы могут проверять, исправлять и улучшать решение со временем.\n4. Комментарии позволяют обсуждать альтернативные подходы или ошибки.\n\nЭта модель намеренно проста. У нас нет формального процесса рецензирования с одобрениями и отклонениями — это замедлило бы работу и отпугнуло бы авторов. Вместо этого мы полагаемся на то, что физика самокорректируется: если в решении есть ошибка, кто-нибудь рано или поздно заметит и исправит. Наша история правок сохраняет каждую версию, так что ничего не теряется.\n\n## Чему мы научились\n\n**Простота масштабируется.** У платформы нет сборки, нет SPA-фреймворка, нет сложного пайплайна деплоя. Это Node.js-сервер, рендерящий EJS-шаблоны и работающий с PostgreSQL. Эта простота позволяет новым авторам легко разобраться в кодовой базе.\n\n**Доверяйте авторам.** Открыть редактирование без шлюзов одобрения казалось рискованным, но это было правильным решением. Подавляющее большинство правок — это настоящие улучшения. Редкие плохие правки быстро замечаются и отменяются.\n\n**Контент — король.** Никакой полировки интерфейса не хватит, если решения неправильны или непонятны. Мы тратим основные усилия на качество решений, а не на функции.\n\n**Длинный хвост имеет значение.** Самые просматриваемые задачи — в ранних главах, но решения, вызывающие больше всего благодарности, часто для малоизвестных задач в поздних главах — тех, для которых студенты просто не могут найти помощь больше нигде.\n\n## Что дальше\n\nМы не закончили. Вот над чем мы работаем:\n\n- **Полное покрытие.** 507 задач до сих пор без решения. Закрыть этот пробел — наша главная задача.\n- **Повышение качества.** Многие ранние решения слишком кратки и выиграли бы от дополнительных объяснений, лучших схем и альтернативных подходов.\n- **Новые функции платформы.** Улучшенный поиск, закладки для решений и этот блог — недавние добавления. Планируется ещё многое.\n- **Рост сообщества.** Мы хотим охватить студентов-физиков в странах и на языках за пределами английского и русского.\n\nКаждое загруженное решение, каждая исправленная ошибка и каждый опубликованный комментарий делают этот ресурс лучше для следующего студента, которому он понадобится. Это двигатель Savchenko Solutions, и он работает исключительно на волонтёрах, которые верят, что хорошее физическое образование должно быть бесплатным.\n\n---\n\n*Хотите внести вклад? Создайте аккаунт и начните редактировать. Каждое исправление на счету.*',
    'От статического сайта на GitHub Pages до платформы с 72 авторами из 18 стран: как вырос Savchenko Solutions и куда он движется.',
    'ru',
    ARRAY['history', 'community', 'announcement'],
    true,
    NOW()
);

COMMIT;
